<!DOCTYPE html>
<html>
<head>
  <title>Personal Expense Tracker</title>
  <style>
    body { font-family: sans-serif; }
    #container { display: flex; }
    #form { width: 30%; padding: 20px; border: 1px solid #ccc; margin-right: 20px; }
    #list { width: 70%; padding: 20px; border: 1px solid #ccc; }
    .expense { display: flex; align-items: baseline; margin-bottom: 5px; }
    .exp-del { background-color: red; color: white; border: none; cursor: pointer; padding: 2px 6px; }
    .cat-total { font-weight: bold; margin-right: 5px; }
  </style>
</head>
<body>

  <h1>Personal Expense Tracker</h1>

  <div id="container">
    <div id="form">
      <label for="amount">Amount:</label>
      <input type="number" id="amount"><br><br>

      <label for="category">Category:</label>
      <select id="category">
        <option value="groceries">Groceries</option>
        <option value="transport">Transport</option>
        <option value="bills">Bills</option>
        <option value="fun">Fun</option>
      </select><br><br>

      <label for="date">Date:</label>
      <input type="date" id="date"><br><br>

      <label for="note">Note (optional):</label>
      <textarea id="note"></textarea><br><br>

      <button id="add-expense">Add Expense</button>
      <p id="form-error"></p>
    </div>

    <div id="list">
      <h2>Expenses</h2>
      <ul class="expenses"></ul>
      <ul>
        <li>Total: <span id="total">0.00</span></li>
      </ul>

      <h3>Category Totals</h3>
      <div class="cat-total" data-cat="groceries"></div>
      <div class="cat-total" data-cat="transport"></div>
      <div class="cat-total" data-cat="bills"></div>
      <div class="cat-total" data-cat="fun"></div>

      <label for="filter-category">Filter Category:</label>
      <select id="filter-category">
        <option value="all">All</option>
      </select><br>

      <label for="filter-from">From Date:</label>
      <input type="date" id="filter-from"><br>

      <label for="filter-to">To Date:</label>
      <input type="date" id="filter-to"><br>
    </div>
  </div>

  <script>
    const expensesList = document.querySelector('.expenses');
    const totalSpan = document.getElementById('total');
    const formError = document.getElementById('form-error');
    const amountInput = document.getElementById('amount');
    const categorySelect = document.getElementById('category');
    const dateInput = document.getElementById('date');
    const noteTextarea = document.getElementById('note');
    const addExpenseButton = document.getElementById('add-expense');
    const filterCategorySelect = document.getElementById('filter-category');
    const filterFromInput = document.getElementById('filter-from');
    const filterToInput = document.getElementById('filter-to');

    let visibleExpenses = [];

    function loadExpenses() {
      const storedExpenses = localStorage.getItem('expenses') || '[]';
      visibleExpenses = JSON.parse(storedExpenses);
      renderExpenses();
      renderCategoryTotals();
      updateTotal();
    }

    function renderExpenses() {
      expensesList.innerHTML = '';
      visibleExpenses.forEach((expense, index) => {
        const listItem = document.createElement('li');
        listItem.className = 'expense';

        const amountText = document.createElement('span');
        amountText.textContent = expense.amount;

        const categoryText = document.createElement('span');
        categoryText.textContent = expense.category;

        const dateText = document.createElement('span');
        dateText.textContent = expense.date;

        const deleteButton = document.createElement('button');
        deleteButton.className = 'exp-del';
        deleteButton.textContent = 'Delete';
        deleteButton.addEventListener('click', () => {
          visibleExpenses = visibleExpenses.filter((_, i) => i !== index);
          renderExpenses();
          updateTotal();
        });

        listItem.appendChild(amountText);
        listItem.appendChild(categoryText);
        listItem.appendChild(dateText);
        listItem.appendChild(deleteButton);
        expensesList.appendChild(listItem);
      });
    }

    function renderCategoryTotals() {
      const categoryTotals = document.querySelectorAll('.cat-total');
      categoryTotals.forEach(element => {
        const cat = element.getAttribute('data-cat');
        let total = 0;
        visibleExpenses.forEach(expense => {
          if (expense.category === cat) {
            total += expense.amount;
          }
        });
        element.textContent = total.toFixed(2);
      });
    }

    function updateTotal() {
      const total = visibleExpenses.reduce((sum, expense) => sum + expense.amount, 0);
      totalSpan.textContent = total.toFixed(2);
    }


    function addExpense(event) {
      event.preventDefault();
      const amount = parseFloat(amountInput.value);
      const category = categorySelect.value;
      const date = dateInput.value;
      const note = noteTextarea.value || '';

      if (isNaN(amount) || amount <= 0 || !date) {
        formError.textContent = 'Please enter a valid amount and date.';
        return;
      }

      const newExpense = { amount, category, date, note };
      visibleExpenses.push(newExpense);
      renderExpenses();
      updateTotal();
      formError.textContent = '';
      amountInput.value = '';
      categorySelect.value = 'groceries';
      dateInput.value = '';
      noteTextarea.value = '';
    }

    function filterExpenses() {
      const selectedCategory = filterCategorySelect.value;
      const fromDate = filterFromInput.value;
      const toDate = filterToInput.value;

      let filteredExpenses = visibleExpenses;

      if (selectedCategory !== 'all') {
        filteredExpenses = visibleExpenses.filter(expense => expense.category === selectedCategory);
      }

      if (fromDate) {
        filteredExpenses = filteredExpenses.filter(expense => new Date(expense.date) >= new Date(fromDate));
      }

      if (toDate) {
        filteredExpenses = filteredExpenses.filter(expense => new Date(expense.date) <= new Date(toDate));
      }

      visibleExpenses = filteredExpenses;
      renderExpenses();
      updateTotal();
    }


    addExpenseButton.addEventListener('click', addExpense);
    filterCategorySelect.addEventListener('change', filterExpenses);
    filterFromInput.addEventListener('change', filterExpenses);
    filterToInput.addEventListener('change', filterExpenses);

    loadExpenses();
  </script>

</body>
</html>
